<span class="line"><span style="--shiki-light:#59873A;--shiki-dark:#80A665;">ln</span><span style="--shiki-light:#A65E2B;--shiki-dark:#C99076;"> -s</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;"> target.txt</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;"> shortcut.txt</span></span>
